import sys
from collections import defaultdict

class TrieNode:
    def __init__(self):
        self.children = defaultdict(TrieNode)
        self.isEndOfWord = False

class Solution:
    def insert(self, s, root):
        node = root
        for ch in s:
            node = node.children[ch - 'A']
        node.isEndOfWord = True

    def getAutoCompletion(self, s, root):
        node = root
        result = []
        for ch in s:
            node = node.children[ch - 'A']
            if node.isEndOfWord:
                result.append(s)
        return result

    def delete(self, s, root):
        self._delete(s, root, 0)

    def _delete(self, s, node, index):
        if index == len(s):
            node.isEndOfWord = False
            return
        ch = s[index]
        if ch not in node.children:
            return
        self._delete(s, node.children[ch], index + 1)
        del node.children[ch]
if __name__ == '__main__':
    sol = Solution()
    root = TrieNode()
    s = input()
    sol.insert(s, root)
    q = input()
    print(sol.getAutoCompletion(q, root))

