#include<bits/stdc++.h>
using namespace std;

const int N = 26;

struct TrieNode {
    TrieNode *children[N];
    bool isEndOfWord;

    TrieNode() {
        for (int i = 0; i  N; i++) children[i] = nullptr;
        isEndOfWord = false;
    }
};

class Solution {
public:
    void insert(string &s, TrieNode *node)
    {
        TrieNode *curr = node;
        for (char ch : s)
        {
            if (curr->children[ch - 'A'] == nullptr)
            {
                curr->children[ch - 'A'] = new TrieNode();
            }
            curr = curr->children[ch - 'A'];
        }
        curr->isEndOfWord = true;
    }

    vector<string> getAutoCompletion(string &s, TrieNode *root)
    {
        vector<string> result;
        TrieNode *node = root;
        for (char ch : s)
        {
            node = node->children[ch - 'A'];
            if (node->isEndOfWord)
            {
                result.push_back(s);
            }
        }
        return result;
    }

    void delete(string &s, TrieNode *node)
    {
        this->_delete(s, node, 0);
    }

    void _delete(string &s, TrieNode *node, int index)
    {
        if (index == s.size())
        {
            node->isEndOfWord = false;
            return;
        }
        char ch = s[index];
        if (node->children[ch - 'A'] == nullptr)
        {
            return;
        }
        _delete(s, node->children[ch - 'A'], index + 1);
        delete node->children[ch - 'A'];
        node->children[ch - 'A'] = nullptr;
    }
};

int main()
{
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    Solution sol;
    int n;
    cin >> n;
    string s;
    cin >> s;
    sol.insert(s, new TrieNode());
    string q;
    cin >> q;
    vector<string> result = sol.getAutoCompletion(q, new TrieNode());
    for (auto &str : result)
    {
        cout  str << endl;
    }
    return 0;
}
